using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Tools ────────────────────────────────────────────────────────
var noteTaker = new NoteTakingTool();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(noteTaker.TakeNote),
        AIFunctionFactory.Create(noteTaker.GetNotes),
    ]
};

// ── Chat client with automatic tool-call handling ────────────────
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── System prompt ────────────────────────────────────────────────
var systemPrompt = new ChatMessage(ChatRole.System, """
    You are a research agent. When the user provides a topic you must:
    1. Search the web with 2-3 different queries to gather broad information.
    2. Take notes on the most important findings as you go.
    3. After gathering enough information, retrieve your notes and synthesize
       them into a well-structured summary with sections and key takeaways.
    Always cite where you found the information when possible.
    """);

// ── Interactive loop ─────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍  AI Research Agent          ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input)) continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    noteTaker.Clear();

    var history = new List<ChatMessage>
    {
        systemPrompt,
        new(ChatRole.User,
            $"Please research the following topic and provide a comprehensive summary: {input}")
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n⏳ Researching… (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(history, chatOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n━━━ Research Summary ━━━━━━━━━━━━━━━━━━━━━━━━");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// ══════════════════════════════════════════════════════════════════
//  Tool: Web Search (via DuckDuckGo HTML endpoint)
// ══════════════════════════════════════════════════════════════════
public static partial class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15)
    };

    [Description("Search the web for information on a topic. Returns the top result titles and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🔎  Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            var titles   = TitleRegex().Matches(html);
            var snippets = SnippetRegex().Matches(html);
            int count    = Math.Min(5, Math.Min(titles.Count, snippets.Count));

            if (count == 0) return "No results found.";

            var sb = new StringBuilder();
            for (int i = 0; i < count; i++)
            {
                sb.AppendLine($"[{i + 1}] {Strip(titles[i].Groups[1].Value)}");
                sb.AppendLine($"    {Strip(snippets[i].Groups[1].Value)}");
                sb.AppendLine();
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string Strip(string h) =>
        WebUtility.HtmlDecode(HtmlTagRegex().Replace(h, "")).Trim();

    [GeneratedRegex(@"<a class=""result__a""[^>]*>(.*?)</a>",        RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"<a class=""result__snippet""[^>]*>(.*?)</a>",  RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

// ══════════════════════════════════════════════════════════════════
//  Tool: Note Taking
// ══════════════════════════════════════════════════════════════════
public class NoteTakingTool
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record important findings while researching.")]
    public string TakeNote(
        [Description("A short title for the note")]      string title,
        [Description("The detailed note content")]        string content)
    {
        _notes.Add((title, content));
        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use before writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes taken yet.";

        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📋  Retrieving {_notes.Count} note(s)");
        Console.ResetColor();

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

